class MyCalendarThree:
    def __init__(self):
        self.events = []
    def book(self, startTime, endTime):
        self.events.append((startTime, endTime))
        points = set()
        for s, e in self.events:
            points.add(s)
            points.add(e)
        best = 0
        for p in points:
            cnt = 0
            for s, e in self.events:
                if s <= p < e:
                    cnt += 1
            best = max(best, cnt)
        return best

