class MyCalendarThree:
    def __init__(self):
        self.delta = {}
    def book(self, startTime, endTime):
        self.delta[startTime] = self.delta.get(startTime, 0) + 1
        self.delta[endTime] = self.delta.get(endTime, 0) - 1
        active = 0
        best = 0
        for t in sorted(self.delta):
            active += self.delta[t]
            if active > best:
                best = active
        return best

